function parse(frame) {
  const bytes = [];
  for (let i = 0; i < frame.length; i += 2) {
    const byte = parseInt(frame.slice(i, i + 2), 16);
    if (!Number.isNaN(byte)) bytes.push(byte);
  }

  const readInt16LE = (offset) => {
    let value = (bytes[offset] || 0) | ((bytes[offset + 1] || 0) << 8);
    if (value & 0x8000) value -= 0x10000;
    return value;
  };
  const readSigned24BE = (offset) => {
    let value = ((bytes[offset] || 0) << 16) | ((bytes[offset + 1] || 0) << 8) | (bytes[offset + 2] || 0);
    if (value & 0x800000) value -= 0x1000000;
    return value;
  };
  const ads24ToVoltage = (raw) => (raw * 2.5) / 8388608.0;
  const tmp117ToCelsius = (offset) => {
    let value = ((bytes[offset] || 0) << 8) | (bytes[offset + 1] || 0);
    if (value & 0x8000) value -= 0x10000;
    return value * 0.0078125;
  };
  const toAccelG = (raw) => {
    const accelG = raw * 0.000488;
    if (accelG === 0) return 0;
    return accelG - Math.sign(accelG);
  };

  const vibrationSamples = 2132;
  const strainSamples = 160;
  const vibrationOffset = 10;
  const strain1Offset = 4274;
  const strain2Offset = 4754;
  const strain3Offset = 5234;
  const adcTempOffset = 5714;
  const tmp117Offset = 5717;

  if (bytes.length < tmp117Offset + 2) return [];

  const accelZ = [];
  for (let i = 0; i < vibrationSamples; i++) {
    accelZ.push(toAccelG(readInt16LE(vibrationOffset + i * 2)));
  }

  const strain1 = [];
  const strain2 = [];
  const strain3 = [];
  for (let i = 0; i < strainSamples; i++) {
    strain1.push(ads24ToVoltage(readSigned24BE(strain1Offset + i * 3)));
    strain2.push(ads24ToVoltage(readSigned24BE(strain2Offset + i * 3)));
    strain3.push(ads24ToVoltage(readSigned24BE(strain3Offset + i * 3)));
  }

  const adcTemp = ads24ToVoltage(readSigned24BE(adcTempOffset));
  const tmp117Temp = tmp117ToCelsius(tmp117Offset);

  return {
    title: 'STM32 Bearing Data',
    datasets: [
      { index: 0, title: 'Accel Z', value: accelZ[accelZ.length - 1], buffer: accelZ },
      { index: 1, title: 'Strain 1', value: strain1[strain1.length - 1], buffer: strain1 },
      { index: 2, title: 'Strain 2', value: strain2[strain2.length - 1], buffer: strain2 },
      { index: 3, title: 'Strain 3', value: strain3[strain3.length - 1], buffer: strain3 },
      { index: 4, title: 'ADC Temp', value: adcTemp },
      { index: 5, title: 'TMP117 Temp', value: tmp117Temp }
    ]
  };
}
